INSERT INTO public.product_translations (product_id, language, content)
VALUES ('c5b9c4ef-9189-44bc-bae9-6997e6b38923', 'th', '## ภาพรวม

จุดเชื่อมต่อไร้สายนี้ให้การเชื่อมต่อเครือข่ายประสิทธิภาพสูงสำหรับสภาพแวดล้อมเชิงพาณิชย์และองค์กร สร้างขึ้นบนมาตรฐาน Wi-Fi ล่าสุด โดยมอบความครอบคลุมไร้สายความเร็วสูงพร้อมการจัดการคลาวด์แบบรวมศูนย์ทั่วทั้งไซต์การใช้งานหลายแห่ง

ออกแบบมาเพื่อการใช้งานเครือข่ายที่ง่ายขึ้นพร้อมการจัดการบนคลาวด์เป็นหลักผ่านแพลตฟอร์ม Reyee

Access Point Reyee Wi-Fi 6 RG-RAP62 ได้รับการออกแบบมาเพื่อมอบประสิทธิภาพที่เชื่อถือได้สำหรับแอปพลิเคชันที่ต้องการโครงสร้างพื้นฐานเครือข่ายและความสามารถในการเชื่อมต่อ RG-RAP62, Wi-Fi 6 AX1800 จุดเข้าใช้งานแบบติดเพดาน ผลิตภัณฑ์นี้ได้รับการสนับสนุนโดยเอกสารประกอบและการสนับสนุนด้านเทคนิคที่ครอบคลุม

## คุณสมบัติ

- มาตรฐานไร้สาย IEEE 802.11ax/ac/n/a พร้อมการทำงานแบบดูอัลแบนด์
- รองรับการรับรองความถูกต้อง WPA3 และ 802.1X ระดับองค์กร
- โหมดการทำงานที่หลากหลาย รวมถึง AP, บริดจ์ และรีพีทเตอร์
